import type { CampingSpot, SurfSchool } from "@camping/domain-shared";

import { haversineKm } from "./geo.ts";

const MAX_NEIGHBORS = 8;
const MAX_KM = 120;

type WithCoords = { latitude: number; longitude: number };

/** Camping spots that list this surf school in `relatedSurfSchoolSlugs` (curated pairings). */
export function campingSpotsLinkedToSurfSchool(
	schoolSlug: string,
	spots: CampingSpot[],
): CampingSpot[] {
	return spots.filter((s) => s.relatedSurfSchoolSlugs?.includes(schoolSlug));
}

/**
 * Curated links first (by distance when coords exist), then geographic neighbors within {@link MAX_KM},
 * deduplicated, capped at {@link MAX_NEIGHBORS}.
 */
export function surfSchoolRelatedCampingOptions(
	school: SurfSchool,
	spots: CampingSpot[],
): CampingSpot[] {
	const origin: WithCoords = {
		latitude: school.latitude,
		longitude: school.longitude,
	};
	const linked = campingSpotsLinkedToSurfSchool(school.slug, spots);
	const nearby = nearbyCampingForSchool(school, spots);
	const bySlug = new Map<string, CampingSpot>();

	const scoreKm = (c: CampingSpot): number | undefined => {
		if (
			c.latitude == null ||
			c.longitude == null ||
			typeof c.latitude !== "number" ||
			typeof c.longitude !== "number"
		) {
			return undefined;
		}
		return haversineKm(
			origin.latitude,
			origin.longitude,
			c.latitude,
			c.longitude,
		);
	};

	const linkedSorted = [...linked].sort((a, b) => {
		const ka = scoreKm(a);
		const kb = scoreKm(b);
		if (ka != null && kb != null) return ka - kb;
		if (ka != null) return -1;
		if (kb != null) return 1;
		return a.name.localeCompare(b.name);
	});
	for (const c of linkedSorted) bySlug.set(c.slug, c);
	for (const c of nearby) {
		if (!bySlug.has(c.slug)) bySlug.set(c.slug, c);
	}
	return Array.from(bySlug.values()).slice(0, MAX_NEIGHBORS);
}

